class Solution {
public:
    vector<int> grayCode(int n) {
        vector<int> res(1 << n);
        for (int i = 0; i < n; i++) {
            for (int j = (1 << i) - 1; j >= 0; j--) {
                res[1 << i + j] = (1 << i) + j;
            }
        }
        return res;
    }
};
